// Route task events — handles both url_verification and app_mention in tasks-* channels
const body = $input.first().json.body || {};
const eventType = body.type || '';

if (eventType === 'url_verification') {
  return [{ json: { route: 'challenge', challenge: body.challenge || '' } }];
}

const event = body.event || {};
if (event.type !== 'app_mention' && event.type !== 'message') {
  return [{ json: { route: 'ignore' } }];
}

// Skip bot messages and retries
if (event.bot_id || event.subtype) {
  return [{ json: { route: 'ignore' } }];
}

const channelId = event.channel || '';
const userId    = event.user    || '';
const rawText   = event.text    || '';
const ts        = event.ts || event.event_ts || '';

// Only handle tasks-* channels
const TASKS_CHANNELS = {
  'C0AKXJSTRV4': 'kevin',
  'C0ALTUECBU0': 'jason',
  'C0AKT93TZAP': 'scaachi',
  'C0AKJ783FF1': 'christian',
  'C0AKJ787K7H': 'chidi'
};

const agent = TASKS_CHANNELS[channelId];
if (!agent) {
  return [{ json: { route: 'ignore' } }];
}

const MODEL_MAP = {
  kevin:     'kevin:latest',
  jason:     'jason:latest',
  scaachi:   'scaachi:latest',
  christian: 'christian:latest',
  chidi:     'chidi:latest'
};

// Agent → output studio channel
const STUDIO_CHANNELS = {
  kevin:     'C0AKW7WT085',  // #studio-blueprint — architecture & design
  jason:     'C0AL38FJ7SQ',  // #studio-forge — code & scripts
  scaachi:   'C0AKJ798RJT',  // #studio-quill — content & copy
  christian: 'C0AKZLGFH50',  // #ops-intel — strategy & business
  chidi:     'C0AKW7WT085',  // #studio-blueprint — research & analysis
};

// Strip bot mention if present
const userText = rawText.replace(/<@[A-Z0-9]+>/g, '').trim();

// Parse structured TASK format if present
const taskMatch     = userText.match(/TASK:\s*(.+?)(?=\nCONTEXT:|\nPRIORITY:|\nDEADLINE:|$)/is);
const contextMatch  = userText.match(/CONTEXT:\s*(.+?)(?=\nTASK:|\nPRIORITY:|\nDEADLINE:|$)/is);
const priorityMatch = userText.match(/PRIORITY:\s*(\w+)/i);

let taskTitle    = '';
let taskContext  = '';
let priority     = 'normal';
let isStructured = false;

if (taskMatch) {
  isStructured  = true;
  taskTitle     = taskMatch[1].trim();
  taskContext   = contextMatch ? contextMatch[1].trim() : '';
  priority      = priorityMatch ? priorityMatch[1].toLowerCase() : 'normal';
}

let prompt;
if (isStructured) {
  prompt = `You have been assigned a task.\n\nTASK: ${taskTitle}${taskContext ? '\n\nCONTEXT: ' + taskContext : ''}\n\nPlease complete this task thoroughly. Provide your full response, analysis, or output.`;
} else {
  prompt = userText;
}

return [{ json: {
  route:         'task',
  agent,
  model:         MODEL_MAP[agent],
  studioChannel: STUDIO_CHANNELS[agent],
  channelId,
  userId,
  ts,
  userText,
  taskTitle,
  taskContext,
  priority,
  isStructured,
  prompt
}}];

function mdToMrkdwn(text) {
  return text
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')
    .replace(/\*\*(.+?)\*\*/gs, '*$1*')
    .replace(/__(.+?)__/gs, '*$1*')
    .replace(/~~(.+?)~~/gs, '~$1~')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const AGENT_EMOJI = {
  kevin:     ':briefcase:',
  jason:     ':gear:',
  scaachi:   ':pencil:',
  christian: ':dart:',
  chidi:     ':microscope:'
};

const STUDIO_LABEL = {
  kevin:     '#studio-blueprint',
  jason:     '#studio-forge',
  scaachi:   '#studio-quill',
  christian: '#ops-intel',
  chidi:     '#studio-blueprint'
};

const ollamaResp = $input.first().json;
const task       = $('Route Task').first().json;

const content   = ollamaResp.message?.content || 'No response.';
const MAX       = 2800;
const formatted = mdToMrkdwn(content);
const truncated = formatted.length > MAX
  ? formatted.slice(0, MAX) + '\n_[truncated — use /ai for longer responses]_'
  : formatted;

const emoji = AGENT_EMOJI[task.agent] || ':robot_face:';
const blocks = [];

if (task.isStructured) {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: '\u2705 ' + task.agent + ' \u2014 task complete', emoji: true }
  });
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: '_' + (task.taskTitle || '').slice(0, 100) + '_' }]
  });
} else {
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: emoji + ' ' + task.agent, emoji: true }
  });
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: 'responding to <@' + task.userId + '>' }]
  });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: truncated } });
blocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `_model: ${task.model}_  \u00b7  _output \u2192 ${STUDIO_LABEL[task.agent] || '#studio-forge'}_`
  }]
});

return [{ json: {
  task,
  rawContent: content,
  channelId:  task.channelId,
  thread_ts:  task.ts,
  payload: JSON.stringify({
    channel:   task.channelId,
    thread_ts: task.ts,
    blocks
  })
}}];

