={{ (() => {
  const teams  = $('Get Linear Team').first().json.data?.teams?.nodes || [];
  const teamId = teams[0]?.id || '';
  const task   = $('Route Task').first().json;
  const output = $('Format Response').first().json.rawContent || '';

  const agentName = task.agent.charAt(0).toUpperCase() + task.agent.slice(1);
  const titleBase = task.taskTitle || task.userText.slice(0, 60);
  const title     = `${agentName}: ${titleBase}`;

  const PRIORITY_MAP = { urgent: 1, high: 2, medium: 3, normal: 3, low: 4 };
  const priority = PRIORITY_MAP[task.priority] || 3;

  const desc =
    `## Task\n${task.userText}\n\n## ${agentName}'s Response\n${output}\n\n---\n` +
    `*Source:* Slack <#${task.channelId}> from <@${task.userId}>\n` +
    `*Model:* ${task.model}\n` +
    `*Repository:* [cschulz-ceo/ai-workers](https://github.com/cschulz-ceo/ai-workers)`;

  const mutation = `
    mutation CreateIssue($input: IssueCreateInput!) {
      issueCreate(input: $input) {
        success
        issue { id identifier title url }
      }
    }
  `;

  const variables = {
    input: {
      teamId,
      title,
      description: desc,
      priority,
      completedAt: new Date().toISOString()
    }
  };

  return JSON.stringify({ query: mutation, variables });
})() }}

={{ (() => {
  const issue = $json.data?.issueCreate?.issue;
  const task  = $('Route Task').first().json;
  if (!issue) return JSON.stringify({ channel: task.channelId, thread_ts: task.ts, text: '_Could not log to Linear \u2014 check LINEAR_API_KEY._' });
  return JSON.stringify({
    channel:   task.channelId,
    thread_ts: task.ts,
    text: `\uD83D\uDD17 _Logged to Linear: <${issue.url}|${issue.identifier}>_`
  });
})() }}

={{ (() => {
  const issue  = $('Create Linear Record').first().json.data?.issueCreate?.issue;
  const task   = $('Route Task').first().json;
  const output = $('Format Response').first().json.rawContent || '';
  const studioChannel = task.studioChannel;
  if (!studioChannel) return '{}';

  const agentName = task.agent.charAt(0).toUpperCase() + task.agent.slice(1);
  const titleBase = task.taskTitle || task.userText.slice(0, 60);
  const issueRef  = issue ? `*<${issue.url}|${issue.identifier}>*  \u00b7  ` : '';
  const preview   = output.length > 600 ? output.slice(0, 600) + '...' : output;

  const AGENT_EMOJI = {
    kevin: '\uD83D\uddFA', jason: '\u2699\uFE0F', scaachi: '\u270D\uFE0F', christian: '\uD83C\uDFAF', chidi: '\uD83D\uDD2C'
  };
  const emoji = AGENT_EMOJI[task.agent] || '\u2705';

  const blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `${emoji}  ${issueRef}*${agentName}* completed: _${titleBase.slice(0, 80)}_`
      }
    },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: preview } },
    {
      type: 'context',
      elements: [{
        type: 'mrkdwn',
        text: `_from <#${task.channelId}>  \u00b7  model: ${task.model}_`
      }]
    }
  ];

  return JSON.stringify({
    channel: studioChannel,
    blocks,
    text: `${emoji} ${agentName} completed: ${titleBase.slice(0, 80)}`
  });
})() }}
